"""REFUGIO submission — cooperative WHCA* + flow lanes + detour + coordinated fallback.

Builds on my base cooperative planner (which already edged the 884 designs) and
adds the three levers the field's current leader uses to push to ~895:
  * a fine-grained 2x3 rack-block layout with 1-cell aisles in BOTH directions
    (a cross aisle at every block boundary -> far less head-on gridlock);
  * soft one-way FLOW lanes (alternating aisle directions + a perimeter ring)
    that bias routing into a circulation pattern, cutting opposing traffic;
  * a detour pass in collision resolution + a plan-aware coordinated step for
    freshly-delivered robots, so almost no move is wasted.

Tunables (FLOW_PENALTY, WINDOW, PRIORITY_MODE) are swept offline.
Only warehouse_api + stdlib. Deterministic.
"""
from __future__ import annotations

import heapq
from collections import deque

from warehouse_api import Action, CellType, Observation

GRID = 52
WMIN, WMAX = 1, 50
INF = 1 << 29

# --- tunables -------------------------------------------------------------
WINDOW = 16         # tuned: short horizon beats 24 (no over-committing)
NODE_CAP = 3000
WAIT_CAP = 30
FLOW_PENALTY = 0.2  # tuned sweet spot (congestion vs detour)
PRIORITY_MODE = 0   # 0=carry/-boost/dist/center 1=carry/dist 2=carry/-boost/dist
BLOCK_H = 3         # shelf block height (3 -> 2x3 grid; 2 -> 2x2 grid)

_DIRS = (
    (Action.UP, 0, -1),
    (Action.DOWN, 0, 1),
    (Action.LEFT, -1, 0),
    (Action.RIGHT, 1, 0),
)


def _nid(x: int, y: int) -> int:
    return y * GRID + x


def _base_entries() -> set[tuple[int, int]]:
    e = set()
    for x in range(3, 50, 2):
        e.add((x, 1))
    for x in range(2, 49, 2):
        e.add((x, 50))
    for y in range(2, 49, 2):
        e.add((1, y))
    for y in range(3, 50, 2):
        e.add((50, y))
    return e


def create_layout() -> dict[str, object]:
    """Fine 2x3 rack-block grid (period 3 x 4), 1-cell aisles both ways, 960 shelves."""
    block_w, block_h, aisle, margin = 2, BLOCK_H, 1, 2
    lo, hi = 1 + margin, 50 - margin
    period_x, period_y = block_w + aisle, block_h + aisle
    cells: list[tuple[int, int]] = []
    x = lo
    while x <= hi:
        y = lo
        while y <= hi:
            for cx in range(x, min(x + block_w, hi + 1)):
                for cy in range(y, min(y + block_h, hi + 1)):
                    cells.append((cx, cy))
            y += period_y
        x += period_x
    entries = _base_entries()
    cells = [c for c in cells if c not in entries]
    n = len(cells)
    extra = n - 960
    if extra > 0:
        removed: set[int] = set()
        for k in range(extra):
            idx = (k * n) // extra + n // (2 * extra)
            while idx in removed:
                idx = (idx + 1) % n
            removed.add(idx)
        cells = [c for i, c in enumerate(cells) if i not in removed]
    return {"schema_version": 1, "shelves": [[x, y] for x, y in cells]}


def _drop_cell(bx: int, by: int) -> tuple[int, int]:
    if bx == 0:
        return (1, by)
    if bx == GRID - 1:
        return (GRID - 2, by)
    if by == 0:
        return (bx, 1)
    return (bx, GRID - 2)


def _adjacent(a, b) -> bool:
    return abs(a[0] - b[0]) + abs(a[1] - b[1]) == 1


class _World:
    __slots__ = ("passable", "nbrs", "flow", "fields")

    def __init__(self, grid) -> None:
        passable = bytearray(GRID * GRID)
        for y in range(WMIN, WMAX + 1):
            row = grid[y]
            for x in range(WMIN, WMAX + 1):
                if row[x] == CellType.EMPTY:
                    passable[_nid(x, y)] = 1
        self.passable = passable
        nbrs: dict[int, tuple[tuple[Action, int], ...]] = {}
        flow: dict[tuple[int, int], float] = {}
        for y in range(WMIN, WMAX + 1):
            for x in range(WMIN, WMAX + 1):
                u = _nid(x, y)
                if not passable[u]:
                    continue
                lst = []
                for action, dx, dy in _DIRS:
                    nx, ny = x + dx, y + dy
                    if WMIN <= nx <= WMAX and WMIN <= ny <= WMAX:
                        v = _nid(nx, ny)
                        if passable[v]:
                            lst.append((action, v))
                            pen = 0.0
                            # vertical aisle columns (x % 3 == 2): alternate up/down
                            if x == nx and x % 3 == 2:
                                if (x // 3) % 2 == 0 and ny > y:
                                    pen = FLOW_PENALTY
                                elif (x // 3) % 2 == 1 and ny < y:
                                    pen = FLOW_PENALTY
                            # horizontal aisle rows: alternate left/right by band
                            elif y == ny and y % (BLOCK_H + 1) == 2:
                                if (y // (BLOCK_H + 1)) % 2 == 0 and nx > x:
                                    pen = FLOW_PENALTY
                                elif (y // (BLOCK_H + 1)) % 2 == 1 and nx < x:
                                    pen = FLOW_PENALTY
                            # perimeter ring highway
                            elif y == 2 and nx > x:
                                pen = FLOW_PENALTY
                            elif y == 49 and nx < x:
                                pen = FLOW_PENALTY
                            elif x == 2 and ny > y:
                                pen = FLOW_PENALTY
                            elif x == 49 and ny < y:
                                pen = FLOW_PENALTY
                            if pen:
                                flow[(u, v)] = pen
                nbrs[u] = tuple(lst)
        self.nbrs = nbrs
        self.flow = flow
        self.fields: dict[tuple, list[int]] = {}

    def _bfs(self, sources):
        dist = [INF] * (GRID * GRID)
        dq = deque()
        for s in sources:
            if dist[s] != 0:
                dist[s] = 0
                dq.append(s)
        nbrs = self.nbrs
        while dq:
            u = dq.popleft()
            du = dist[u] + 1
            for _a, v in nbrs[u]:
                if dist[v] > du:
                    dist[v] = du
                    dq.append(v)
        return dist

    def base_field(self, entry):
        key = ("B", entry)
        f = self.fields.get(key)
        if f is None:
            f = self._bfs([entry])
            self.fields[key] = f
        return f

    def shelf_field(self, shelf):
        key = ("S", shelf)
        f = self.fields.get(key)
        if f is None:
            sx, sy = shelf
            srcs = []
            for _a, dx, dy in _DIRS:
                nx, ny = sx + dx, sy + dy
                if WMIN <= nx <= WMAX and WMIN <= ny <= WMAX:
                    m = _nid(nx, ny)
                    if self.passable[m]:
                        srcs.append(m)
            f = self._bfs(srcs)
            self.fields[key] = f
        return f


class _Brain:
    __slots__ = (
        "world", "tick", "pos", "entry", "target", "carrying", "wait",
        "moves", "occupied", "locked", "greedy", "claimed", "pfinal", "pstart",
    )

    def __init__(self):
        self.world = None
        self.tick = None
        self.pos = {}; self.entry = {}; self.target = {}; self.carrying = {}
        self.wait = {}; self.moves = {}
        self.occupied = frozenset(); self.locked = frozenset(); self.greedy = frozenset()
        self.claimed = set(); self.pfinal = {}; self.pstart = {}

    def reset(self):
        self.tick = None
        self.pos.clear(); self.entry.clear(); self.target.clear(); self.carrying.clear()
        self.wait.clear(); self.moves.clear()
        self.occupied = frozenset(); self.locked = frozenset(); self.greedy = frozenset()
        self.claimed = set(); self.pfinal = {}; self.pstart = {}


_BRAIN = _Brain()


def _base_act(observation: Observation) -> Action:
    try:
        return _act(observation)
    except Exception:
        return Action.WAIT


def _act(obs):
    brain = _BRAIN
    if brain.world is None:
        brain.world = _World(obs.grid)
    if brain.tick is None or obs.tick != brain.tick:
        if brain.tick is None or obs.tick < brain.tick:
            brain.reset()
        brain.tick = obs.tick
        try:
            _plan(brain, obs)
        except Exception:
            brain.moves = {}
    return _action_for(brain, obs)


def _plan(brain, obs0):
    world = brain.world
    positions = obs0.all_robot_positions
    r0 = obs0.robot_id
    brain.entry[r0] = _nid(*_drop_cell(*obs0.base_position))
    brain.target[r0] = obs0.target_item_position
    brain.carrying[r0] = obs0.carrying_item
    for rid, xy in positions.items():
        brain.pos[rid] = (xy[0], xy[1])
    rids = sorted(positions)
    brain.occupied = frozenset(brain.pos[rid] for rid in rids)
    brain.locked = frozenset(
        t for rid in rids
        if brain.carrying.get(rid) and (t := brain.target.get(rid)) is not None
    )

    stayers, movers, greedy = [], [], []
    field_of = {}
    for rid in rids:
        n = _nid(*brain.pos[rid])
        if brain.carrying.get(rid, False):
            entry = brain.entry.get(rid)
            if entry is None:
                stayers.append(rid); continue
            field = world.base_field(entry)
            if n == entry:
                stayers.append(rid); continue
        else:
            target = brain.target.get(rid)
            if target is None:
                stayers.append(rid); greedy.append(rid); continue
            field = world.shelf_field(target)
            if field[n] == 0:
                stayers.append(rid); continue
        if field[n] >= INF:
            stayers.append(rid); continue
        field_of[rid] = field
        movers.append(rid)
    brain.greedy = frozenset(greedy)

    cell_res, edge_res = {}, {}
    for rid in stayers:
        n = _nid(*brain.pos[rid])
        for t in range(WINDOW + 1):
            cell_res[(t, n)] = rid

    def priority(rid):
        pos = brain.pos[rid]
        n = _nid(*pos)
        carry = 0 if brain.carrying.get(rid) else 1
        boost = -min(brain.wait.get(rid, 0), WAIT_CAP)
        dist = field_of[rid][n]
        center = abs(pos[0] - 25) + abs(pos[1] - 25)
        if PRIORITY_MODE == 1:
            return (carry, dist, rid)
        if PRIORITY_MODE == 2:
            return (carry, boost, dist, rid)
        return (carry, boost, dist, center, rid)

    movers.sort(key=priority)

    desired = {rid: _nid(*brain.pos[rid]) for rid in rids}
    for rid in movers:
        start = _nid(*brain.pos[rid])
        path = _astar(world, start, field_of[rid], cell_res, edge_res)
        if path is None or len(path) < 2:
            desired[rid] = start
            for t in range(WINDOW + 1):
                cell_res.setdefault((t, start), rid)
            continue
        desired[rid] = path[1]
        last = len(path) - 1
        for i in range(min(last, WINDOW) + 1):
            cell_res[(i, path[i])] = rid
        for i in range(min(last, WINDOW)):
            edge_res[(i, path[i], path[i + 1])] = rid
        for t in range(last + 1, WINDOW + 1):
            cell_res[(t, path[last])] = rid

    order = stayers + movers
    final = _resolve(brain, desired, order)

    moves, starts = {}, {}
    for rid in rids:
        u = _nid(*brain.pos[rid]); v = final[rid]
        starts[rid] = u
        moves[rid] = _delta(u, v)
        brain.wait[rid] = 0 if v != u else brain.wait.get(rid, 0) + 1
    brain.moves = moves
    brain.pfinal = dict(final)
    brain.pstart = starts
    brain.claimed = set(final.values())


def _astar(world, start, field, cell_res, edge_res):
    if field[start] >= INF:
        return None
    if field[start] == 0:
        return [start]
    nbrs = world.nbrs
    flow = world.flow
    open_heap = [(float(field[start]), 0.0, start, 0)]
    came = {}
    gbest = {(start, 0): 0.0}
    expansions = 0
    goal_state = None
    while open_heap:
        f, g, n, t = heapq.heappop(open_heap)
        if g > gbest.get((n, t), INF):
            continue
        if field[n] == 0:
            goal_state = (n, t)
            break
        expansions += 1
        if expansions > NODE_CAP:
            break
        nt = t + 1
        within = nt <= WINDOW
        for _a, m in nbrs[n]:
            if within and ((nt, m) in cell_res or (t, m, n) in edge_res):
                continue
            ng = g + 1.0 + flow.get((n, m), 0.0)
            key = (m, nt)
            if ng < gbest.get(key, INF):
                gbest[key] = ng
                came[key] = (n, t)
                heapq.heappush(open_heap, (ng + field[m], ng, m, nt))
        if not (within and (nt, n) in cell_res):
            ng = g + 1.01
            key = (n, nt)
            if ng < gbest.get(key, INF):
                gbest[key] = ng
                came[key] = (n, t)
                heapq.heappush(open_heap, (ng + field[n], ng, n, nt))
    if goal_state is None:
        return None
    path = []
    st = goal_state
    while st in came:
        path.append(st[0]); st = came[st]
    path.append(start)
    path.reverse()
    return path


def _resolve(brain, desired, order):
    cur = {rid: _nid(*brain.pos[rid]) for rid in desired}
    final = dict(desired)
    by_cur = {cur[rid]: rid for rid in desired}
    for rid in order:
        u, v = cur[rid], final[rid]
        if v == u:
            continue
        other = by_cur.get(v)
        if other is not None and other != rid and final.get(other) == u:
            final[rid] = u
            final[other] = cur[other]
    occ = {}
    blocked = set()
    for rid in order:
        v = final[rid]
        if v in occ:
            final[rid] = cur[rid]
            blocked.add(rid)
        else:
            occ[v] = rid
            if v == cur[rid]:
                blocked.add(rid)
    world = brain.world
    for rid in order:
        if rid not in blocked or final[rid] != cur[rid]:
            continue
        if desired[rid] == cur[rid]:
            continue
        u = cur[rid]
        for _a, v in world.nbrs[u]:
            if v not in occ:
                other = by_cur.get(v)
                if other is not None and final[other] == u:
                    continue
                final[rid] = v
                occ[v] = rid
                break
    return final


def _delta(u, v):
    if u == v:
        return Action.WAIT
    dx = (v % GRID) - (u % GRID)
    if dx == 1:
        return Action.RIGHT
    if dx == -1:
        return Action.LEFT
    return Action.DOWN if (v // GRID) - (u // GRID) == 1 else Action.UP


def _action_for(brain, obs):
    rid = obs.robot_id
    pos = obs.position
    brain.pos[rid] = pos
    brain.entry[rid] = _nid(*_drop_cell(*obs.base_position))
    brain.target[rid] = obs.target_item_position
    brain.carrying[rid] = obs.carrying_item
    if obs.carrying_item:
        if _nid(*pos) == brain.entry[rid]:
            brain.carrying[rid] = False
            brain.target[rid] = None
            return Action.DROP
    else:
        if _adjacent(pos, obs.target_item_position) and obs.target_item_position not in brain.locked:
            brain.carrying[rid] = True
            return Action.PICKUP
    move = brain.moves.get(rid)
    if move is None or (move == Action.WAIT and rid in brain.greedy):
        move = _coord_step(brain, obs)
    return move


def _coord_step(brain, obs):
    world = brain.world
    rid = obs.robot_id
    x, y = obs.position
    cnode = _nid(x, y)
    if obs.carrying_item:
        field = world.base_field(_nid(*_drop_cell(*obs.base_position)))
    else:
        target = obs.target_item_position
        if target is None:
            return Action.WAIT
        field = world.shelf_field(target)
    claimed = brain.claimed
    pfinal = brain.pfinal
    pstart = brain.pstart
    best_action = Action.WAIT
    best_node = cnode
    best_key = (field[cnode], y, x)
    for action, dx, dy in _DIRS:
        nx, ny = x + dx, y + dy
        if not (WMIN <= nx <= WMAX and WMIN <= ny <= WMAX):
            continue
        m = _nid(nx, ny)
        if not world.passable[m]:
            continue
        if m != cnode and m in claimed:
            continue
        swap = False
        for orid, fnode in pfinal.items():
            if orid != rid and fnode == cnode and pstart.get(orid) == m:
                swap = True
                break
        if swap:
            continue
        key = (field[m], ny, nx)
        if key < best_key:
            best_key = key
            best_action = action
            best_node = m
    if best_node != cnode:
        claimed.discard(cnode)
        claimed.add(best_node)
        pfinal[rid] = best_node
        pstart[rid] = cnode
    return best_action

