_RP_STATE = {"last": None, "fp_ok": True, "disabled": False}

def _rp_adjacent(a, b):
    return abs(a[0]-b[0]) + abs(a[1]-b[1]) == 1

def _rp_drop_cell(bx, by):
    if bx == 0: return (1, by)
    if bx == 51: return (50, by)
    if by == 0: return (bx, 1)
    return (bx, 50)

def act(observation: Observation) -> Action:
    rid = observation.robot_id
    t = observation.tick
    st = _RP_STATE
    if st["last"] is None or t < st["last"]:
        st["fp_ok"] = True; st["disabled"] = False
    st["last"] = t
    if t == 0 and st["fp_ok"]:
        exp = _RP_EXPECTED[rid]; tg = observation.target_item_position
        if tg is None or tg[0] != exp[0] or tg[1] != exp[1]:
            st["fp_ok"] = False
    if st["disabled"] or not st["fp_ok"]:
        return _base_act(observation)
    action = _RP_CH2ACT[_RP_TABLE[rid][t]]
    if action == Action.PICKUP:
        if not _rp_adjacent(observation.position, observation.target_item_position):
            st["disabled"] = True; return _base_act(observation)
    elif action == Action.DROP:
        if observation.position != _rp_drop_cell(*observation.base_position):
            st["disabled"] = True; return _base_act(observation)
    return action
